CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "role" varchar check ("role" in ('super_admin', 'admin')) not null default 'admin', "company_id" integer, foreign key("company_id") references "companies"("id") on delete set null);
