CREATE TABLE IF NOT EXISTS "pages" ("id" integer primary key autoincrement not null, "company_id" integer not null, "title" varchar not null, "slug" varchar not null, "meta_title" varchar, "meta_description" text, "is_published" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("company_id") references "companies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "sections" ("id" integer primary key autoincrement not null, "page_id" integer not null, "type" varchar not null, "content" text, "order" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "media" ("id" integer primary key autoincrement not null, "company_id" integer not null, "file_path" varchar not null, "file_type" varchar, "created_at" datetime, "updated_at" datetime, "original_name" varchar, foreign key("company_id") references "companies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "company_id" integer not null, "key" varchar not null, "value" text, "created_at" datetime, "updated_at" datetime, foreign key("company_id") references "companies"("id") on delete cascade);
